INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Excel avancé niveau 1 & 2', 'Formation Excel avancé pour maîtriser les fonctions complexes, l’analyse de données et la création de dashboards professionnels.', 5, 150000.00, 'entreprise', '2026-05-10', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Maîtriser les fonctionnalités avancées d’Excel\n• Automatiser les calculs et analyses\n• Exploiter efficacement les données\n• Produire des tableaux de bord professionnels\n• Gagner en productivité et fiabilité\n\n--- OBJECTIFS DÉTAILLÉS ---\nMaîtriser les fonctionnalités avancées d’Excel, automatiser les calculs et analyses, exploiter les données efficacement, produire des tableaux de bord professionnels et améliorer la productivité.\n\n--- PRÉREQUIS ---\nConnaissances de base en Excel pour le Niveau 1. Bonne maîtrise des fonctions et TCD pour le Niveau 2.\n\n--- CONTENU ---\nNiveau 1 : Rappels essentiels et bonnes pratiques, Fonctions avancées indispensables, Gestion et analyse des données, Tableaux croisés dynamiques (TCD), Introduction aux graphiques avancés, Cas pratiques.\nNiveau 2 : Formules complexes et fonctions modernes, Tableaux croisés dynamiques avancés, Power Query (ETL), Power Pivot & DAX, Automatisation avec macros (VBA), Tableaux de bord professionnels, Cas pratiques avancés.\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nUtilisateurs d’Excel ayant déjà les bases (Niveau 1) et utilisateurs avancés souhaitant automatiser et analyser (Niveau 2).\n\n--- MÉTHODES ---\nPrésentations interactives, démonstrations, ateliers pratiques, études de cas, projets encadrés et simulations.\n\n--- SUPPORTS ---\nExcel (versions récentes), Power Query, Power Pivot, VBA, tableurs, supports PDF, modèles pratiques et vidéos pédagogiques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
